import { Page } from '@playwright/test';
import { test, expect } from '../../fixtures/cdp.fixture';
import { waitForAppReady } from '../../fixtures/helpers';

// ---------------------------------------------------------------------------
// Shared helpers (navigation, frame locators)
// ---------------------------------------------------------------------------

/** Navigate to the Matched Pairs Inventory via the menu system. */
async function openMatchedPairsInventory(mainPage: Page) {
  // Top-level menu: "Tools" (or similar, adjust when UI is built)
  await mainPage.getByRole('menuitem', { name: /Tools/i }).click();

  // Sub-menu: "Checking inventories"
  await mainPage.getByRole('menuitem', { name: /Checking inventories/i }).click();

  // Sub-menu item: "Unmatched pairs of punctuation"
  await mainPage.getByRole('menuitem', { name: /Unmatched pairs of punctuation/i }).click();

  // Wait for the dock tab to appear
  const tab = mainPage.locator('.dock-tab', {
    hasText: /Unmatched Pairs of Punctuation/i,
  });
  await expect(tab).toBeVisible({ timeout: 30_000 });
}

/** Return a FrameLocator for the inventory form web view iframe. */
function inventoryFrame(mainPage: Page) {
  return mainPage.frameLocator('iframe[title*="Unmatched Pairs of Punctuation Inventory"]');
}

/** Return a FrameLocator for the CMS options dialog iframe. */
function optionsDialogFrame(mainPage: Page) {
  return mainPage.frameLocator('iframe[title="Inventory Options"]');
}

